/**
 * @brief Calculates simple checksum for firmware integrity verification
 */
static uint32_t calculate_checksum(const unsigned char* data, size_t size)
{
    uint32_t checksum = 0;
    size_t i;

    for (i = 0; i < size; i++) {
        checksum = ((checksum << 5) + checksum) + data[i]; /* Jenkins hash */
    }

    return checksum;
}

/**
 * @brief Verifies firmware integrity using embedded checksum
 * @return 1 if valid, 0 if invalid
 */
static int verify_firmware_integrity(const unsigned char* data, size_t size)
{
    uint32_t expected_checksum;
    uint32_t calculated_checksum;

    if (size < sizeof(uint32_t)) {
        return 0;  /* Too small to contain checksum */
    }

    /* Last 4 bytes are checksum (little-endian) */
    expected_checksum = (uint32_t)data[size - 4] |
                       ((uint32_t)data[size - 3] << 8) |
                       ((uint32_t)data[size - 2] << 16) |
                       ((uint32_t)data[size - 1] << 24);

    calculated_checksum = calculate_checksum(data, size - sizeof(uint32_t));

    return (expected_checksum == calculated_checksum) ? 1 : 0;
}

